  ('optician-moex-01468', 'optician', 'optician-moex-109-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '要維持眼睛正視屈光狀態，與下列眼睛生理參數何者最有關？①瞳孔直徑  ②角膜曲率  ③水晶體曲率', '["視網膜曲率", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:34+00:00", "source_pdf_sha1": "0e99d0ca894b", "answer_pdf_sha1": "b01b4ba5666a", "source_family": "moex-gov-tw", "moex": {"exam_code": "109060", "c": "402", "s": "0807", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "109", "exam_name": "109年專技人員高等考試大地工程技師考試分階段考試（第一階段考試）、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 2, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL)
